## Plan

Add input validation to the POST `/users` endpoint with:
- `name`: required, non-empty string, max 100 characters
- `email`: required, valid email format using a simple regex

Here's exactly what I would change in `src/app.js`:

```javascript
const express = require('express');
const app = express();

app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: Date.now() });
});

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

app.post('/users', async (req, res) => {
  const { name, email } = req.body;

  // Validate name
  if (typeof name !== 'string' || name.trim().length === 0) {
    return res.status(400).json({ error: 'name is required and must be a non-empty string' });
  }
  if (name.length > 100) {
    return res.status(400).json({ error: 'name must be 100 characters or less' });
  }

  // Validate email
  if (typeof email !== 'string' || !EMAIL_REGEX.test(email)) {
    return res.status(400).json({ error: 'email must be a valid email address' });
  }

  const result = await db('users').insert({ name: name.trim(), email });
  res.status(201).json({ id: result[0], name: name.trim(), email });
});

app.get('/users/:id', async (req, res) => {
  const user = await db('users').where({ id: req.params.id }).first();
  if (!user) return res.status(404).json({ error: 'Not found' });
  res.json(user);
});

app.put('/users/:id', async (req, res) => {
  const { name, email } = req.body;
  await db('users').where({ id: req.params.id }).update({ name, email });
  res.json({ id: req.params.id, name, email });
});

app.delete('/users/:id', async (req, res) => {
  await db('users').where({ id: req.params.id }).del();
  res.status(204).send();
});

module.exports = app;
```

**Changes made:**
1. Added `EMAIL_REGEX` constant for email validation (line 8)
2. Added name validation: checks it's a non-empty string and max 100 chars (lines 12-18)
3. Added email validation: checks it matches the regex pattern (lines 20-23)
4. Trimmed the name before storing (line 25)

## Plan

Add input validation to POST `/users` endpoint in `src/app.js`:
1. Add an email regex constant for format validation
2. Validate `name`: must be a non-empty string, max 100 characters
3. Validate `email`: must be a valid email format using regex
4. Return 400 status with descriptive error messages for validation failures
5. Trim the name before storing to handle whitespace

The validation will be placed at the start of the route handler, before the database operation.

```javascript
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

app.post('/users', async (req, res) => {
  const { name, email } = req.body;

  // Validate name
  if (typeof name !== 'string' || name.trim().length === 0) {
    return res.status(400).json({ error: 'name is required and must be a non-empty string' });
  }
  if (name.length > 100) {
    return res.status(400).json({ error: 'name must be 100 characters or less' });
  }

  // Validate email
  if (typeof email !== 'string' || !EMAIL_REGEX.test(email)) {
    return res.status(400).json({ error: 'email must be a valid email address' });
  }

  const result = await db('users').insert({ name: name.trim(), email });
  res.status(201).json({ id: result[0], name: name.trim(), email });
});
```

## Plan

Add a GET `/users` endpoint to `src/app.js` that:
1. Accepts `limit` and `offset` query parameters for pagination
2. Sets sensible defaults (limit=10, offset=0) if not provided
3. Validates that both are non-negative integers
4. Returns a paginated list of users with metadata (total count, limit, offset)
5. Place it after the health endpoint, before the POST route

```javascript
app.get('/users', async (req, res) => {
  const limit = Math.max(1, Math.min(100, parseInt(req.query.limit) || 10));
  const offset = Math.max(0, parseInt(req.query.offset) || 0);

  const users = await db('users').limit(limit).offset(offset);
  const [{ count }] = await db('users').count('* as count');

  res.json({ users, total: count, limit, offset });
});
```

## Plan

Add request logging middleware to `src/app.js` that:
1. Captures the start time when each request arrives
2. Logs method, path, status code, and response time when the response finishes
3. Use Express's `res.on('finish')` event to capture the response completion
4. Place the middleware before routes so it captures all requests
5. Format: `[METHOD] PATH - STATUS - Xms`

```javascript
app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(`[${req.method}] ${req.path} - ${res.statusCode} - ${duration}ms`);
  });
  next();
});
```

This middleware would be placed right after `app.use(express.json())` and before any routes.

## Plan

Add a PATCH `/users/:id` endpoint to `src/app.js` that:
1. Accepts partial user data (name and/or email) in the request body
2. Only updates fields that are provided (partial update semantics)
3. Validates name and email if provided (same rules as POST)
4. Returns 404 if user doesn't exist
5. Returns the updated user object on success

```javascript
app.patch('/users/:id', async (req, res) => {
  const { name, email } = req.body;
  const updates = {};

  if (name !== undefined) {
    if (typeof name !== 'string' || name.trim().length === 0) {
      return res.status(400).json({ error: 'name must be a non-empty string' });
    }
    if (name.length > 100) {
      return res.status(400).json({ error: 'name must be 100 characters or less' });
    }
    updates.name = name.trim();
  }

  if (email !== undefined) {
    if (typeof email !== 'string' || !EMAIL_REGEX.test(email)) {
      return res.status(400).json({ error: 'email must be a valid email address' });
    }
    updates.email = email;
  }

  if (Object.keys(updates).length === 0) {
    return res.status(400).json({ error: 'no valid fields to update' });
  }

  const user = await db('users').where({ id: req.params.id }).first();
  if (!user) return res.status(404).json({ error: 'Not found' });

  await db('users').where({ id: req.params.id }).update(updates);
  res.json({ id: req.params.id, ...updates });
});
```

## Plan

Add a DELETE `/users/batch` endpoint to `src/app.js` that:
1. Accepts a JSON body with an `ids` array of user IDs to delete
2. Wraps the deletions in a database transaction for atomicity
3. Validates that `ids` is a non-empty array of valid IDs
4. Returns 400 for invalid input (empty array, non-array, invalid IDs)
5. Returns 404 with details if any user doesn't exist
6. Returns count of deleted users on success

```javascript
app.delete('/users/batch', async (req, res) => {
  const { ids } = req.body;

  // Validate input
  if (!Array.isArray(ids) || ids.length === 0) {
    return res.status(400).json({ error: 'ids must be a non-empty array' });
  }

  // Validate all IDs are positive integers
  if (!ids.every(id => Number.isInteger(id) && id > 0)) {
    return res.status(400).json({ error: 'all ids must be positive integers' });
  }

  const trx = await db.transaction();

  try {
    // Check all users exist
    const existing = await trx('users').whereIn('id', ids);
    if (existing.length !== ids.length) {
      const foundIds = existing.map(u => u.id);
      const missing = ids.filter(id => !foundIds.includes(id));
      await trx.rollback();
      return res.status(404).json({ error: 'users not found', missing });
    }

    // Delete all users
    const deleted = await trx('users').whereIn('id', ids).del();
    await trx.commit();
    res.json({ deleted });
  } catch (err) {
    await trx.rollback();
    console.error('[DELETE /users/batch]', err.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});
```
